import React, { useState } from 'react';

export default function Tabs({ tabs, initial = 0 }) {
  const [active, setActive] = useState(initial);

  if (!tabs || tabs.length === 0) return null;

  const onKeyDown = (e) => {
    if (e.key === 'ArrowRight') setActive((i) => (i + 1) % tabs.length);
    if (e.key === 'ArrowLeft') setActive((i) => (i - 1 + tabs.length) % tabs.length);
  };

  return (
    <div style={{ maxWidth: 480 }}>
      <div role="tablist" onKeyDown={onKeyDown} style={{ display: 'flex', borderBottom: '2px solid #eee' }}>
        {tabs.map((tab, i) => (
          <button
            key={tab.label}
            role="tab"
            aria-selected={i === active}
            tabIndex={i === active ? 0 : -1}
            onClick={() => setActive(i)}
            style={{
              padding: '10px 16px',
              border: 'none',
              background: 'none',
              cursor: 'pointer',
              fontSize: 15,
              fontWeight: i === active ? 700 : 500,
              color: i === active ? '#2563eb' : '#555',
              borderBottom: i === active ? '2px solid #2563eb' : '2px solid transparent',
              marginBottom: -2,
            }}
          >
            {tab.label}
          </button>
        ))}
      </div>
      <div role="tabpanel" style={{ padding: 16, lineHeight: 1.5 }}>
        {tabs[active].content}
      </div>
    </div>
  );
}

