import { Component, Input, OnInit } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface Tab { label: string; content: string; }

@Component({
  selector: 'app-tabs',
  template: `
    <div *ngIf="tabs.length" style="max-width: 480px;">
      <div role="tablist" (keydown)="onKey($event)" style="display: flex; border-bottom: 2px solid #eee;">
        <button
          *ngFor="let tab of tabs; let i = index"
          role="tab"
          (click)="active = i"
          [attr.aria-selected]="i === active"
          [attr.tabindex]="i === active ? 0 : -1"
          [style.font-weight]="i === active ? 700 : 500"
          [style.color]="i === active ? '#2563eb' : '#555'"
          [style.border-bottom]="i === active ? '2px solid #2563eb' : '2px solid transparent'"
          style="padding: 10px 16px; border: none; background: none; cursor: pointer; font-size: 15px; margin-bottom: -2px;"
        >
          {{ tab.label }}
        </button>
      </div>
      <div role="tabpanel" style="padding: 16px; line-height: 1.5;">{{ tabs[active].content }}</div>
    </div>
  `,
})
export class TabsComponent implements OnInit {
  @Input() tabs: Tab[] = [];
  @Input() initial = 0;
  active = 0;

  ngOnInit(): void {
    this.active = this.initial;
  }

  onKey(e: KeyboardEvent): void {
    if (e.key === 'ArrowRight') this.active = (this.active + 1) % this.tabs.length;
    if (e.key === 'ArrowLeft') this.active = (this.active - 1 + this.tabs.length) % this.tabs.length;
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Tabs Demo</h1>
      <app-tabs [tabs]="tabs" [initial]="0"></app-tabs>
    </div>
  `,
})
export class AppComponent {
  tabs: Tab[] = [
    { label: 'Overview', content: 'A tabs component lets users switch between related views in the same space.' },
    { label: 'Accessibility', content: 'Use role=tablist/tab/tabpanel, aria-selected, and arrow-key navigation.' },
    { label: 'Tips', content: 'Keep labels short and render the panel for the active tab only.' },
  ];
}

@NgModule({
  declarations: [AppComponent, TabsComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
